    15→import { request as httpRequest, RequestOptions } from 'http';
    16→
    17→import { readEnvFile } from './env.js';
    18→import { logger } from './logger.js';
    19→
    20→export type AuthMode = 'api-key' | 'oauth';
    21→
    22→export interface ProxyConfig {
    23→  authMode: AuthMode;
    24→}
