    32→    'CLAUDE_CODE_OAUTH_TOKEN',
    33→    'ANTHROPIC_AUTH_TOKEN',
    34→    'ANTHROPIC_BASE_URL',
    35→  ]);
    36→
    37→  const authMode: AuthMode = secrets.ANTHROPIC_API_KEY ? 'api-key' : 'oauth';
    38→  const oauthToken =
    39→    secrets.CLAUDE_CODE_OAUTH_TOKEN || secrets.ANTHROPIC_AUTH_TOKEN;
    40→
    41→  const upstreamUrl = new URL(
    42→    secrets.ANTHROPIC_BASE_URL || 'https://api.anthropic.com',
    43→  );
    44→  const isHttps = upstreamUrl.protocol === 'https:';
    45→  const makeRequest = isHttps ? httpsRequest : httpRequest;
    46→
    47→  return new Promise((resolve, reject) => {
    48→    const server = createServer((req, res) => {
    49→      const chunks: Buffer[] = [];
    50→      req.on('data', (c) => chunks.push(c));
    51→      req.on('end', () => {
    52→        const body = Buffer.concat(chunks);
    53→        const headers: Record<string, string | number | string[] | undefined> =
    54→          {
    55→            ...(req.headers as Record<string, string>),
    56→            host: upstreamUrl.host,
    57→            'content-length': body.length,
    58→          };
    59→
    60→        // Strip hop-by-hop headers that must not be forwarded by proxies
    61→        delete headers['connection'];
    62→        delete headers['keep-alive'];
    63→        delete headers['transfer-encoding'];
    64→
