   182→  // Advance cursor so the piping path in startMessageLoop won't re-fetch
   183→  // these messages. Save the old cursor so we can roll back on error.
   184→  const previousCursor = lastAgentTimestamp[chatJid] || '';
   185→  lastAgentTimestamp[chatJid] =
   186→    missedMessages[missedMessages.length - 1].timestamp;
   187→  saveState();
