   194→  // Track idle timer for closing stdin when agent is idle
   195→  let idleTimer: ReturnType<typeof setTimeout> | null = null;
   196→
   197→  const resetIdleTimer = () => {
   198→    if (idleTimer) clearTimeout(idleTimer);
   199→    idleTimer = setTimeout(() => {
   200→      logger.debug(
   201→        { group: group.name },
   202→        'Idle timeout, closing container stdin',
   203→      );
