   212→  const output = await runAgent(group, prompt, chatJid, async (result) => {
   213→    // Streaming output callback — called for each agent result
   214→    if (result.result) {
   215→      const raw =
   216→        typeof result.result === 'string'
   217→          ? result.result
   218→          : JSON.stringify(result.result);
   219→      // Strip <internal>...</internal> blocks — agent uses these for internal reasoning
   220→      let text = raw.replace(/<internal>[\s\S]*?<\/internal>/g, '');
   221→      // <disengage:userId/> — disengage a specific user
   222→      // <disengage/> or <disengage:all/> — disengage all users (group mode off)
   223→      const disengageMatches = text.matchAll(
