   232→        }
   233→      }
   234→      text = text
   235→        .replace(/<disengage[^>]*\/?>/g, '')
   236→        .replace(/<\/disengage>/g, '')
   237→        .trim();
   238→      logger.info({ group: group.name }, `Agent output: ${raw.slice(0, 200)}`);
   239→      if (text) {
