   155→export function startIpcWatcher(deps: IpcDeps): void {
   156→  if (ipcWatcherRunning) {
   157→    logger.debug('IPC watcher already running, skipping duplicate start');
   158→    return;
   159→  }
   160→  ipcWatcherRunning = true;
   161→
   162→  const expectedBuildId = readExpectedBuildId();
   163→
   164→  const ipcBaseDir = path.join(DATA_DIR, 'ipc');
   165→  fs.mkdirSync(ipcBaseDir, { recursive: true });
   166→
   167→  // Safe unlink that tolerates ENOENT (file already processed by concurrent watcher)
   168→  const safeUnlink = (filePath: string) => {
   169→    try {
   170→      fs.unlinkSync(filePath);
   171→    } catch (e: unknown) {
   172→      if ((e as NodeJS.ErrnoException).code !== 'ENOENT') throw e;
   173→    }
   174→  };
   175→
   176→  const processIpcFiles = async () => {
   177→    // Scan all group IPC directories (identity determined by directory)
   178→    let groupFolders: string[];
   179→    try {
   180→      groupFolders = fs
   181→        .readdirSync(ipcBaseDir, { withFileTypes: true })
   182→        .filter((d) => d.isDirectory() && d.name !== 'errors')
   183→        .map((d) => d.name);
   184→    } catch (err) {
   185→      logger.error({ err }, 'Error reading IPC base directory');
   186→      return;
   187→    }
   188→
   189→    const registeredGroups = deps.registeredGroups();
   190→
   191→    // Build folder→isMain lookup from registered groups
   192→    const folderIsMain = new Map<string, boolean>();
   193→    for (const group of Object.values(registeredGroups)) {
   194→      if (group.isMain) folderIsMain.set(group.folder, true);
   195→    }
   196→
   197→    for (const sourceGroup of groupFolders) {
   198→      const isMain = folderIsMain.get(sourceGroup) === true;
   199→      const messagesDir = path.join(ipcBaseDir, sourceGroup, 'messages');
   200→      const tasksDir = path.join(ipcBaseDir, sourceGroup, 'tasks');
   201→
   202→      // Process messages from this group's IPC directory
   203→      try {
   204→        if (fs.existsSync(messagesDir)) {
   205→          const messageFiles = fs
   206→            .readdirSync(messagesDir)
   207→            .filter((f) => f.endsWith('.json'));
   208→          for (const file of messageFiles) {
   209→            const filePath = path.join(messagesDir, file);
   210→            try {
   211→              let raw: string;
   212→              try {
   213→                raw = fs.readFileSync(filePath, 'utf-8');
   214→              } catch (readErr: unknown) {
   215→                // File already processed by a concurrent watcher — skip
   216→                if ((readErr as NodeJS.ErrnoException).code === 'ENOENT')
   217→                  continue;
   218→                throw readErr;
   219→              }
   220→              const data = JSON.parse(raw);
   221→              if (
   222→                expectedBuildId &&
   223→                data.buildId &&
   224→                data.buildId !== expectedBuildId
   225→              ) {
   226→                logger.debug(
   227→                  { file, dataBuildId: data.buildId, expectedBuildId },
   228→                  'Dropping IPC message from old image',
   229→                );
   230→                safeUnlink(filePath);
   231→                continue;
   232→              }
   233→              if (data.type === 'message' && data.chatJid && data.text) {
   234→                // Authorization: verify this group can send to this chatJid
   235→                const targetGroup = registeredGroups[data.chatJid];
   236→                if (
   237→                  isMain ||
   238→                  (targetGroup && targetGroup.folder === sourceGroup)
   239→                ) {
   240→                  if (
   241→                    sourceGroup === 'telegram_ollama' &&
   242→                    (data.chatJid.startsWith('tg:') ||
   243→                      data.chatJid.startsWith('tg-j:'))
   244→                  ) {
   245→                    await sendJarvisMessage(data.chatJid, data.text);
   246→                  } else if (data.sender && data.chatJid.startsWith('tg:')) {
   247→                    await sendPoolMessage(
   248→                      data.chatJid,
   249→                      data.text,
   250→                      data.sender,
   251→                      sourceGroup,
   252→                    );
   253→                  } else {
   254→                    await deps.sendMessage(data.chatJid, data.text);
   255→                  }
   256→                  logger.info(
   257→                    { chatJid: data.chatJid, sourceGroup },
   258→                    'IPC message sent',
   259→                  );
   260→                } else {
   261→                  logger.warn(
   262→                    { chatJid: data.chatJid, sourceGroup },
   263→                    'Unauthorized IPC message attempt blocked',
   264→                  );
   265→                }
   266→              } else if (data.type === 'status' && data.chatJid && data.text) {
   267→                // Status messages (stopped/online) — edit if last was status, new if user activity since
   268→                const targetGroup = registeredGroups[data.chatJid];
   269→                if (
